-- Seed track catalog from legacy SQLite database.
-- This migration is idempotent and safe to re-run.

ON CONFLICT (id) DO UPDATE SET
    artist = EXCLUDED.artist,
    name = EXCLUDED.name,
    path = EXCLUDED.path;

SELECT setval(pg_get_serial_sequence('russian', 'id'), COALESCE((SELECT MAX(id) FROM russian), 1), true);

ON CONFLICT (id) DO UPDATE SET
    artist = EXCLUDED.artist,
    name = EXCLUDED.name,
    path = EXCLUDED.path;

SELECT setval(pg_get_serial_sequence('english', 'id'), COALESCE((SELECT MAX(id) FROM english), 1), true);

